/* bauhaus — enforce Bauhaus catalogue geometry */

/* ── Zero radius everywhere ── */
*,
*::before,
*::after {
  border-radius: 0 !important;
}

/* ── Card chrome: flat, 2 px cobalt border, no shadow ── */
.wp-block-woocommerce-product-list .wc-block-product,
.wc-block-grid__product,
.wp-block-post,
.wo-product-card,
.wc-block-components-product-image,
.wc-block-product-template li {
  border: 2px solid var(--wp--preset--color--border) !important;
  box-shadow: none !important;
  background: var(--wp--preset--color--surface);
  border-radius: 0 !important;
}

/* ── No hover elevation ── */
.wp-block-woocommerce-product-list .wc-block-product:hover,
.wc-block-grid__product:hover,
.wo-product-card:hover {
  box-shadow: none !important;
  transform: none !important;
}

/* ── Section dividers ── */
.wp-block-group + .wp-block-group,
.wp-block-separator {
  border-top: 2px solid var(--wp--preset--color--border);
}

/* ── Section vertical padding: condensed ── */
.wp-block-group.alignfull,
.wp-block-group.alignwide {
  padding-top: var(--wp--preset--spacing--lg) !important;
  padding-bottom: var(--wp--preset--spacing--lg) !important;
}

/* ── Hero band: cream base, full-width, no image bleed ── */
.wp-block-cover.bauhaus-hero,
.wp-block-group.bauhaus-hero {
  background-color: var(--wp--preset--color--base) !important;
  background-image: none !important;
}

/* ── Primary CTA button: outline, no fill, uppercase tracked ── */
.wp-block-button__link,
.wc-block-components-button,
.button,
button {
  background: transparent !important;
  color: var(--wp--preset--color--contrast) !important;
  border: 2px solid var(--wp--preset--color--contrast) !important;
  box-shadow: none !important;
  border-radius: 0 !important;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: 600;
  padding: 0.5rem 1.25rem;
}

.wp-block-button__link:hover,
.wc-block-components-button:hover,
.button:hover,
button:hover {
  background: var(--wp--preset--color--contrast) !important;
  color: var(--wp--preset--color--base) !important;
  box-shadow: none !important;
}

/* ── Price figures: accent yellow only ── */
.wc-block-components-product-price,
.price,
.woocommerce-Price-amount,
.wc-block-grid__product-price {
  color: var(--wp--preset--color--accent) !important;
  font-weight: 700;
}

/* ── Section headings: display font, uppercase, tracked ── */
h1, h2, h3, h4, h5, h6,
.wp-block-heading {
  font-family: var(--wp--preset--font-family--display);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--wp--preset--color--contrast);
}

/* ── Body copy: sans, muted ── */
body, p, li {
  font-family: var(--wp--preset--font-family--sans);
  font-weight: 400;
  line-height: 1.5;
  color: var(--wp--preset--color--muted);
}

/* ── Links: cobalt underline only ── */
a {
  color: inherit;
  text-decoration-color: var(--wp--preset--color--border);
  text-decoration: underline;
}
a:hover {
  color: var(--wp--preset--color--border);
}

/* ── Navigation links: no underline ── */
.wp-block-navigation a,
.wp-block-navigation-item__content {
  text-decoration: none !important;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-size: 0.8rem;
}

/* ── Product grid: 4-col, 1 rem gap, no masonry ── */
.wc-block-product-template,
.wc-block-grid__products {
  display: grid !important;
  grid-template-columns: repeat(4, 1fr) !important;
  gap: 1rem !important;
  align-items: start;
}

@media (max-width: 900px) {
  .wc-block-product-template,
  .wc-block-grid__products {
    grid-template-columns: repeat(2, 1fr) !important;
  }
}

@media (max-width: 480px) {
  .wc-block-product-template,
  .wc-block-grid__products {
    grid-template-columns: 1fr !important;
  }
}

/* ── Add to Cart buttons inside grid: full-width, outline ── */
.wc-block-grid__product .wp-block-button__link,
.wc-block-product-template .wp-block-button__link {
  width: 100%;
  text-align: center;
  font-size: 0.75rem;
  padding: 0.35rem 0.5rem;
}

/* ── Input fields: no radius, 2 px border ── */
input, select, textarea {
  border: 2px solid var(--wp--preset--color--border) !important;
  border-radius: 0 !important;
  box-shadow: none !important;
  background: var(--wp--preset--color--surface);
}

/* ── Mini-cart / totals buttons: inherit outline style ── */
.wc-block-mini-cart__footer-actions a,
.wc-block-components-totals-coupon__button,
.wc-block-cart__submit-container .wc-block-components-checkout-place-order-button {
  border-radius: 0 !important;
}

/* ── Dense hero-to-grid transition ── */
.bauhaus-hero + .wp-block-group,
.bauhaus-hero + section {
  margin-top: 0 !important;
  padding-top: var(--wp--preset--spacing--sm) !important;
}
